SELECT total_cost
FROM fuel_records
WHERE fuel_id = 0;

SELECT total_cost
FROM fuel_records
WHERE truck_id = 0;

SELECT SUM(load_value) AS total_load_value
FROM load_records
WHERE load_status = 'delivered';

SELECT truck_id, COUNT(*) AS total_loads
   FROM load_records
   GROUP BY truck_id;

SELECT load_number, delivery_date
FROM load_records
WHERE delivery_date > '2023-10-15';
